#!/usr/bin/env sh
set -eu

root_dir=$(CDPATH= cd -- "$(dirname -- "$0")/.." && pwd)
cd "$root_dir"

echo "== Semantic surface audit =="

check_file=
check_dir=

cleanup() {
  if [ -n "$check_dir" ]; then
    rm -rf "$check_dir"
  fi
  if [ -n "$check_file" ]; then
    rm -f "$check_file"
  fi
}

trap cleanup EXIT

